```class Solution {
    public String lastSubstring(String s) {
        int maxIndex = 0, maxEnd = 0;
        for (int i = 1; i < s.length(); i++) {
            int j = i;
            while (j > maxIndex && s.charAt(j) <= s.charAt(maxIndex)) {
                j--;
            }
            if (j > maxIndex) {
                maxIndex = j;
                maxEnd = i;
            }
        }
        return s.substring(maxEnd);
    }
